        if (!file_exists($documentPath)) {
            $this->markTestSkipped('Skipping code_javascript_basic: missing document at ' . $documentPath);
        }

        Helpers::skipIfFeatureUnavailable('tree-sitter');

        $config = Helpers::buildConfig(null);

        $kreuzberg = new Kreuzberg($config);
        $result = $kreuzberg->extractFile($documentPath);

        Helpers::assertExpectedMime($result, ['text/x-source-code']);
        Helpers::assertMinContentLength($result, 10);
        Helpers::assertContentContainsAll($result, ['class Application', 'export function', 'import']);
    }

